window.B1_LESSONS = [
    { number: 1, unit: "Block 1", title: "Life So Far", objective: "Talk about experiences and recent changes with more independence.", cefr: "Can describe experiences and recent changes in connected sentences.", focus: "Present perfect with ever, never and just", warmup: "What is one thing you have done recently that made you proud?", checkpoint: ["Talk about experiences without focusing on exact time.", "Use present perfect to connect the past with the present."], dialogueTitle: "A quick life update", dialogue: [["Teacher", "You look happy today. What has changed?"], ["Student", "I have just finished a short online course for work."], ["Teacher", "Have you ever studied this topic before?"], ["Student", "No, but I have learned a lot."]], grammar: { title: "Present perfect for experience and result", intro: "Use present perfect for experiences, recent results and unfinished time connected to now.", points: [["Experience", "have/has + past participle", "I have visited three different states this year."], ["Recent result", "have/has + just + past participle", "She has just sent the email."], ["Question", "Have/Has + subject + past participle?", "Have you ever worked from home?"], ["Negative", "have/has not + past participle", "He has never driven abroad."]] }, vocabTitle: "Experiences and progress", vocabulary: [["achievement", "conquista", "Getting that certificate was a big achievement."], ["milestone", "marco", "Buying her first car was a milestone."], ["improve", "melhorar", "My listening has improved a lot."], ["experience", "experiencia", "Teaching children was a new experience."], ["challenge", "desafio", "Speaking in public is still a challenge."], ["progress", "progresso", "You can see real progress now."]], production: { title: "Share two personal updates", steps: ["Mention one recent achievement.", "Mention one experience you have never had.", "Ask a follow-up question using Have you ever...?"], model: "I have just started a new routine, and I have already noticed a difference. Have you ever changed your routine because of work?" }, homework: "Write six sentences about your life so far: three things you have done, two things you have never done and one thing you have just completed.", celebration: "B1 starts to feel real when the learner can connect personal experience to the present with clear and confident sentences." },
    { number: 2, unit: "Block 1", title: "Since, For, Already, Yet", objective: "Express duration and unfinished time periods more accurately.", cefr: "Can describe how long situations have continued and ask for updates.", focus: "Present perfect with since, for, already and yet", warmup: "How long have you had your current routine, job or study plan?", checkpoint: ["Use since with a starting point and for with a duration.", "Use yet in questions and negatives."], dialogueTitle: "Checking progress", dialogue: [["Teacher", "How long have you worked in your current job?"], ["Student", "I have worked there for almost two years."], ["Teacher", "Have you finished your training yet?"], ["Student", "Not yet, but I have already completed the first part."]], grammar: { title: "Duration and unfinished situations", intro: "Use present perfect when a situation started in the past and continues now, or when something is or is not complete.", points: [["Starting point", "since + date / event", "I have lived here since 2022."], ["Duration", "for + period", "She has studied English for three years."], ["Completed earlier", "already", "They have already booked the tickets."], ["Not complete yet", "yet", "We have not decided yet."]] }, vocabTitle: "Time and progress markers", vocabulary: [["deadline", "prazo", "The deadline has already passed."], ["phase", "fase", "We are still in the first phase."], ["continue", "continuar", "The project has continued longer than expected."], ["so far", "ate agora", "So far, the results look good."], ["recently", "recentemente", "I have been very busy recently."], ["ongoing", "em andamento", "It is still an ongoing conversation."]], production: { title: "Give a progress report", steps: ["Say how long you have done something.", "Mention one thing you have already finished.", "Mention one thing you have not done yet."], model: "I have studied in the evenings for six months. I have already finished one book, but I have not taken a full speaking test yet." }, homework: "Write a short update about your work, studies or health routine using since, for, already and yet at least once each.", celebration: "This lesson gives the learner more control over time expressions, which is a key step from A2 to B1." },
    { number: 3, unit: "Block 1", title: "Experiences and Milestones", objective: "Compare experiences and explain what was difficult, useful or memorable.", cefr: "Can describe important events and explain why they mattered.", focus: "Present perfect plus detail sentences in past simple", warmup: "What is one experience that changed the way you think?", checkpoint: ["Use present perfect to introduce the experience.", "Use past simple to add when, where or how details."], dialogueTitle: "Looking back at a turning point", dialogue: [["Teacher", "Have you ever had a trip that changed you?"], ["Student", "Yes, I have. I visited another city alone last year."], ["Teacher", "Why was it important for you?"], ["Student", "It was the first time I solved everything by myself."]], grammar: { title: "Mixing present perfect and past simple", intro: "Introduce an experience with present perfect, then move to past simple when you add a finished-time detail.", points: [["Open the topic", "Have you ever...?", "Have you ever worked with tourists?"], ["Add time detail", "past simple", "Yes, I worked with tourists in 2023."], ["Explain impact", "because / so / which is why", "It was hard, so I became more patient."], ["Follow-up", "What happened when...?", "What happened when you arrived there?"]] }, vocabTitle: "Milestones and reflection", vocabulary: [["turning point", "ponto de virada", "That interview was a turning point."], ["memorable", "memoravel", "It was a memorable conversation."], ["independent", "independente", "Living alone made her more independent."], ["confident", "confiante", "After that course, I felt more confident."], ["adapt", "adaptar", "You learn to adapt quickly."], ["grow", "crescer", "Difficult moments can help you grow."]], production: { title: "Describe a milestone", steps: ["Name one experience you have had.", "Add a finished-time detail.", "Explain how it changed you."], model: "I have had a very important learning experience. I gave my first presentation at work last year, and it made me more confident." }, homework: "Prepare a one-minute story about an important milestone in your life using one present perfect sentence and at least three past simple sentences.", celebration: "At B1, the learner no longer gives isolated facts only; they start connecting experience, detail and personal meaning." },
    { number: 4, unit: "Block 1", title: "Used To and Change Over Time", objective: "Talk about past habits, old routines and personal change.", cefr: "Can describe changes in habits, preferences and lifestyles.", focus: "Used to for past habits and states", warmup: "What did you use to do that you do not do anymore?", checkpoint: ["Use used to for old habits or situations that are no longer true.", "Contrast the past with now."], dialogueTitle: "Then and now", dialogue: [["Teacher", "Did you use to enjoy studying online?"], ["Student", "Not really. I used to prefer face-to-face classes."], ["Teacher", "And what about now?"], ["Student", "Now I like both, because online classes save time."]], grammar: { title: "Used to for habits and states in the past", intro: "Use used to when a past habit or situation was true before but is not true now.", points: [["Affirmative", "subject + used to + base verb", "I used to wake up very late."], ["Negative", "did not use to + base verb", "She did not use to cook."], ["Question", "Did + subject + use to + base verb?", "Did they use to live here?"], ["Contrast", "but now / these days", "I used to be shy, but now I speak more."]] }, vocabTitle: "Change and routine", vocabulary: [["habit", "habito", "Changing a habit takes time."], ["routine", "rotina", "My routine is more organized now."], ["lifestyle", "estilo de vida", "He changed his lifestyle."], ["save time", "economizar tempo", "Working from home can save time."], ["prefer", "preferir", "I used to prefer paper books."], ["these days", "hoje em dia", "These days, I read more online."]], production: { title: "Talk about a personal change", steps: ["Mention one past habit with used to.", "Say what is different now.", "Explain the reason for the change."], model: "I used to study only before exams, but now I review a little every day because I want better long-term results." }, homework: "Write a short paragraph called Then and now with four sentences about your past routine and four about your current routine.", celebration: "Talking about change over time helps the learner tell richer personal stories instead of only describing the present." },
    { number: 5, unit: "Block 1", title: "Future Plans and Arrangements", objective: "Discuss plans, appointments and personal arrangements naturally.", cefr: "Can talk about future plans and make practical arrangements.", focus: "Present continuous and going to for future plans", warmup: "What are you doing this weekend, and what are you going to do next month?", checkpoint: ["Use present continuous for arranged plans.", "Use going to for intentions and planned actions."], dialogueTitle: "Planning ahead", dialogue: [["Teacher", "Are you doing anything special this Friday?"], ["Student", "Yes, I am meeting a friend after work."], ["Teacher", "And what are you going to do next month?"], ["Student", "I am going to start a short design course."]], grammar: { title: "Two future forms for practical plans", intro: "Present continuous often sounds more concrete, while going to highlights intention or plan.", points: [["Arrangement", "present continuous", "We are meeting at 7."], ["Intention", "be going to + base verb", "I am going to save more money."], ["Question", "What are you doing...?", "What are you doing after class?"], ["Time markers", "tomorrow / next week / this weekend", "They are traveling next Tuesday."]] }, vocabTitle: "Plans and arrangements", vocabulary: [["appointment", "compromisso", "I have a dentist appointment tomorrow."], ["schedule", "agenda", "My schedule is full this week."], ["book", "reservar", "We need to book the hotel soon."], ["reschedule", "remarcar", "Can we reschedule the meeting?"], ["available", "disponivel", "Are you available on Thursday?"], ["plan ahead", "planejar", "I try to plan ahead when I travel."]], production: { title: "Make two future plans", steps: ["Describe one arranged plan for this week.", "Describe one intention for the next few months.", "Invite someone or ask a follow-up question."], model: "I am having lunch with a friend on Saturday, and I am going to look for a new course next month. Are you planning anything new?" }, homework: "Create a mini calendar with five future sentences: two arrangements, two intentions and one question for a partner.", celebration: "Clear future language lets the learner move from simple conversation into real-life planning and coordination." },
    { number: 6, unit: "Block 1", title: "Predictions and Possibilities", objective: "Talk about uncertain future events and expectations.", cefr: "Can express predictions, probability and uncertainty with simple support.", focus: "Will, might, probably and maybe", warmup: "What do you think will happen in your area of work or study this year?", checkpoint: ["Use will for predictions and quick decisions.", "Use might, maybe and probably to sound less certain."], dialogueTitle: "Thinking about the future", dialogue: [["Teacher", "Do you think remote work will stay common?"], ["Student", "Yes, I think it will stay important for many companies."], ["Teacher", "Will everything become online?"], ["Student", "Maybe not. Some teams might prefer a mixed model."]], grammar: { title: "Prediction and possibility", intro: "Will predicts or decides in the moment. Might and probably make the statement less absolute.", points: [["Prediction", "will + base verb", "People will need more digital skills."], ["Possibility", "might + base verb", "We might move to a new office."], ["Certainty marker", "probably", "She will probably call later."], ["Soft opinion", "maybe", "Maybe the prices will go down."]] }, vocabTitle: "Future thinking", vocabulary: [["trend", "tendencia", "This trend is growing fast."], ["predict", "prever", "Experts predict higher demand."], ["uncertain", "incerto", "The next few months still feel uncertain."], ["likely", "provavel", "It is likely that sales will increase."], ["unlikely", "improvavel", "It seems unlikely right now."], ["outcome", "resultado", "We do not know the final outcome yet."]], production: { title: "Make three predictions", steps: ["Predict one thing about work or study.", "Mention one possibility with might.", "Add one sentence with probably or maybe."], model: "I think online courses will become more flexible. Some companies might invest more in training, and students will probably expect faster feedback." }, homework: "Write five predictions about technology, education or your personal future. Use will at least twice and might at least once.", celebration: "The learner now has language to talk about the future with more nuance instead of sounding 100 percent sure all the time." },
    { number: 7, unit: "Block 1", title: "First Conditional in Real Life", objective: "Build confidence with real possible future conditions and consequences.", cefr: "Can explain likely results of real future situations.", focus: "First conditional with if", warmup: "If you have a free day this week, what will you do?", checkpoint: ["Use present simple after if.", "Use will in the result clause."], dialogueTitle: "Practical decisions", dialogue: [["Teacher", "What will you do if the weather gets worse?"], ["Student", "If it gets worse, I will stay home and study."], ["Teacher", "And if you finish early?"], ["Student", "If I finish early, I will go for a walk."]], grammar: { title: "First conditional for likely future results", intro: "Use the first conditional when the condition is real or possible in the future.", points: [["Pattern", "If + present simple, will + base verb", "If I have time, I will call you."], ["Reverse order", "Will + base verb if + present simple", "I will call you if I have time."], ["Negative", "if + do not / does not", "If she does not practice, she will forget."], ["Common use", "plans, warnings, promises", "If you send it today, I will review it."]] }, vocabTitle: "Decisions and consequences", vocabulary: [["consequence", "consequencia", "Every decision has a consequence."], ["option", "opcao", "This is our best option right now."], ["backup plan", "plano B", "Always have a backup plan."], ["delay", "atraso", "If there is a delay, we will wait."], ["solve", "resolver", "We will solve it together."], ["cancel", "cancelar", "They might cancel the event."]], production: { title: "Talk about real possibilities", steps: ["Mention a real future condition.", "Say the expected result.", "Add a second condition about a different situation."], model: "If I finish work early, I will cook at home. If I feel too tired, I will order something simple instead." }, homework: "Write seven first conditional sentences about work, money, health or study decisions.", celebration: "This lesson helps the learner move from isolated statements to cause-and-effect thinking, which is central at B1." },
    { number: 8, unit: "Block 1 Review", title: "Review 1: Past, Present and Future", objective: "Review key B1 tools from the first block and move between time frames with confidence.", cefr: "Can switch between present results, past habits and future plans in a simple connected way.", focus: "Integrated review", warmup: "Can you tell a short story about your past, present and near future in six sentences?", checkpoint: ["Choose the correct time frame more consciously.", "Move from one tense to another without losing clarity."], dialogueTitle: "A full personal update", dialogue: [["Teacher", "Tell me something about your past, present and future."], ["Student", "I used to study only at night, but now I review every day."], ["Teacher", "What have you achieved recently?"], ["Student", "I have already finished two units, and next month I am going to take a new test."]], grammar: { title: "Choosing the right frame", intro: "At B1, learners should select grammar based on meaning: result now, habit then, plan later or likely consequence.", points: [["Experience now", "present perfect", "I have improved my speaking."], ["Past habit", "used to", "I used to avoid meetings."], ["Future arrangement", "present continuous / going to", "I am meeting my tutor tomorrow."], ["Real result", "first conditional", "If I keep practicing, I will improve."]] }, vocabTitle: "Review language", vocabulary: [["update", "atualizacao", "Let me give you a quick update."], ["goal", "meta", "My next goal is to speak more naturally."], ["result", "resultado", "The result has been positive so far."], ["change", "mudanca", "This change has helped a lot."], ["plan", "plano", "The plan is simple and realistic."], ["step", "passo", "Every lesson is one step forward."]], production: { title: "Three-time-frame challenge", steps: ["Say one thing you used to do.", "Say one thing you have achieved recently.", "Say one thing you are going to do soon."], model: "I used to leave everything for the last minute. I have recently become more organized, and I am going to keep this habit in the next few months." }, homework: "Write a personal review called Then, now and next with three sentences about the past, three about the present and three about the future.", celebration: "After this review, the learner has a stronger bridge between A2 content and the more flexible communication expected at B1." },
    { number: 9, unit: "Block 2", title: "Opinions and Polite Disagreement", objective: "Share opinions clearly while staying polite and open.", cefr: "Can express opinions and respond to other views in simple discussion.", focus: "Opinion phrases and polite disagreement", warmup: "What topics are easy for you to discuss, and which ones feel more difficult?", checkpoint: ["Use clear opinion phrases instead of only yes or no.", "Disagree politely and give one reason."], dialogueTitle: "A calm discussion", dialogue: [["Teacher", "Do you think people learn better alone?"], ["Student", "In my opinion, some people do, but not everyone."], ["Teacher", "I see your point, but I think group work helps motivation."], ["Student", "That is true. I guess it depends on the learner."]], grammar: { title: "Useful phrases for discussion", intro: "At B1, learners should move beyond simple likes and dislikes and start building opinions with support and polite reactions.", points: [["Giving an opinion", "I think / In my opinion", "In my opinion, online classes can be effective."], ["Soft disagreement", "I see your point, but...", "I see your point, but some students need more structure."], ["Partial agreement", "That is true, but...", "That is true, but it is not enough for everyone."], ["Summarizing", "It depends on...", "It depends on the context."]] }, vocabTitle: "Discussion language", vocabulary: [["point of view", "ponto de vista", "That is an interesting point of view."], ["argue", "argumentar", "She can argue her ideas calmly."], ["evidence", "evidencia", "Good evidence makes an opinion stronger."], ["convincing", "convincente", "Your example was convincing."], ["balanced", "equilibrado", "Try to give a balanced answer."], ["consider", "considerar", "We should consider both sides."]], production: { title: "Give and defend an opinion", steps: ["Choose one everyday topic.", "State your opinion.", "Add one reason and one polite reaction to another possible view."], model: "In my opinion, hybrid work can be very effective because it saves time and still allows collaboration. I understand that some teams prefer being together every day, though." }, homework: "Write two short opinion paragraphs, one about study habits and one about technology. Include one polite disagreement sentence in each.", celebration: "This lesson begins the B1 shift from answering questions to participating in simple discussions." },
    { number: 10, unit: "Block 2", title: "Making Suggestions and Decisions", objective: "Propose options, react to ideas and reach a decision together.", cefr: "Can make suggestions, negotiate simple choices and agree on plans.", focus: "Should, could, lets and why dont we", warmup: "How do you normally make decisions with other people at work or at home?", checkpoint: ["Make suggestions with a friendly tone.", "React to ideas and move toward a decision."], dialogueTitle: "Choosing the next step", dialogue: [["Teacher", "We need a new study plan. What should we change first?"], ["Student", "We could start with shorter sessions during the week."], ["Teacher", "Why do not we add one speaking session too?"], ["Student", "Great idea. Let us try that for two weeks."]], grammar: { title: "Suggestion language for collaboration", intro: "These structures make conversation sound more cooperative and practical.", points: [["Advice", "should + base verb", "You should take notes after class."], ["Option", "could + base verb", "We could try another time."], ["Proposal", "Let's + base verb", "Let's meet online first."], ["Question form", "Why don't we + base verb?", "Why don't we review the plan now?"]] }, vocabTitle: "Decision-making language", vocabulary: [["option", "opcao", "We have two good options."], ["approach", "abordagem", "This approach may work better."], ["practical", "pratico", "Let us choose the most practical solution."], ["efficient", "eficiente", "That seems more efficient."], ["solve", "resolver", "We need to solve this together."], ["decide", "decidir", "We should decide before Friday."]], production: { title: "Make a group decision", steps: ["Present a problem to solve.", "Give two suggestions using should or could.", "Finish with a decision using let's."], model: "We are wasting time in long meetings. We could send updates before the meeting, and we should keep the discussion shorter. Let us test that next week." }, homework: "Write a short team message with three suggestions for improving study, work or home organization.", celebration: "The learner is now practicing interactive language that sounds practical, collaborative and closer to real B1 communication." },
    { number: 11, unit: "Block 2", title: "Comparatives, Too and Enough", objective: "Compare options and explain what is excessive or sufficient.", cefr: "Can compare alternatives and explain practical limits.", focus: "Comparatives plus too and enough", warmup: "When you compare products, courses or jobs, what do you look at first?", checkpoint: ["Use comparatives to evaluate two options.", "Use too and enough to talk about limits and adequacy."], dialogueTitle: "Choosing the better option", dialogue: [["Teacher", "Which course looks better for you?"], ["Student", "The online one is cheaper and more flexible."], ["Teacher", "Is the other one too expensive?"], ["Student", "Yes, and it is not practical enough for my schedule."]], grammar: { title: "Comparing and evaluating", intro: "B1 learners use comparatives not just for facts, but for decisions. Too and enough add useful meaning about limits.", points: [["Short adjectives", "-er than", "This option is faster than the other one."], ["Long adjectives", "more + adjective + than", "The second plan is more realistic."], ["Excess", "too + adjective", "It is too expensive."], ["Sufficiency", "adjective + enough", "The room is large enough."]] }, vocabTitle: "Evaluating options", vocabulary: [["affordable", "acessivel", "This course is more affordable."], ["reliable", "confiavel", "We need a more reliable service."], ["flexible", "flexivel", "A flexible plan works better for me."], ["convenient", "conveniente", "The location is convenient enough."], ["efficient", "eficiente", "This tool is much more efficient."], ["suitable", "adequado", "It is suitable for beginners."]], production: { title: "Compare two real options", steps: ["Choose two products, plans or places.", "Compare price, convenience or quality.", "Say whether one option is too expensive, too far or good enough."], model: "The second plan is more affordable and easier to manage. The first one looks interesting, but it is too expensive for me right now." }, homework: "Compare two courses, jobs or apps in a short paragraph using at least three comparatives, one too phrase and one enough phrase.", celebration: "This lesson helps the learner sound more precise when they evaluate options instead of only saying good or bad." },
    { number: 12, unit: "Block 2", title: "Advice, Rules and Expectations", objective: "Expand control of advice, obligation and expectation in work and daily life.", cefr: "Can explain rules, give advice and talk about what is expected.", focus: "Should, must, have to and be supposed to", warmup: "What rules or expectations are common in your work, studies or family life?", checkpoint: ["Differentiate advice from obligation.", "Use be supposed to for expected behavior."], dialogueTitle: "What is expected here?", dialogue: [["Teacher", "Do employees have to answer messages at night?"], ["Student", "Not always, but they are supposed to reply during working hours."], ["Teacher", "What should a new employee do first?"], ["Student", "They should learn the process and ask clear questions."]], grammar: { title: "Advice, rules and expectations", intro: "These structures help B1 learners explain the difference between good ideas, strong rules and normal expectations.", points: [["Advice", "should + base verb", "You should ask for feedback."], ["Strong rule", "must + base verb", "You must wear an ID badge."], ["External obligation", "have to + base verb", "We have to submit the report today."], ["Expectation", "be supposed to + base verb", "You are supposed to arrive on time."]] }, vocabTitle: "Workplace and daily expectations", vocabulary: [["policy", "politica", "The company policy is very clear."], ["requirement", "requisito", "English is a requirement for this role."], ["responsibility", "responsabilidade", "Time management is part of the role."], ["expectation", "expectativa", "The expectations are high but realistic."], ["guideline", "orientacao", "Please read the safety guidelines."], ["professional", "profissional", "Professional behavior matters."]], production: { title: "Explain expectations in a context", steps: ["Choose a place such as an office, school or gym.", "Give one piece of advice.", "Give one rule and one expected behavior."], model: "In a new office, you should ask questions early. You must protect confidential information, and you are supposed to communicate respectfully with everyone." }, homework: "Write a guide for a new student or employee with two should sentences, two have to or must sentences and one supposed to sentence.", celebration: "The learner can now sound more responsible and practical when talking about behavior in real settings." },
    { number: 13, unit: "Block 2", title: "Relative Clauses for Clearer Descriptions", objective: "Describe people, places and things more naturally by linking ideas.", cefr: "Can describe people and objects in a more connected, less repetitive way.", focus: "Defining and non-defining relative clauses", warmup: "How can relative clauses make your speaking sound less repetitive?", checkpoint: ["Use who, which and that to connect information.", "Add extra detail more naturally."], dialogueTitle: "Explaining what you mean", dialogue: [["Teacher", "Tell me about a person who has influenced you."], ["Student", "My aunt, who works in education, has always encouraged me."], ["Teacher", "And what is one tool that helps you study?"], ["Student", "I use an app that reminds me to review vocabulary every day."]], grammar: { title: "Relative clauses to connect ideas", intro: "Relative clauses help B1 learners speak and write more smoothly by joining related information into one sentence.", points: [["People", "who", "I know a teacher who explains things clearly."], ["Things", "which / that", "This is the book that helped me most."], ["Places", "where", "That is the city where I studied."], ["Extra information", "comma + who/which", "My brother, who lives abroad, calls every week."]] }, vocabTitle: "Description and connection", vocabulary: [["influence", "influenciar", "She influenced the way I study."], ["tool", "ferramenta", "A good tool saves time."], ["resource", "recurso", "This is a useful learning resource."], ["reliable", "confiavel", "I need a reliable platform."], ["support", "apoio", "Family support makes a difference."], ["organize", "organizar", "I use a system that helps me organize ideas."]], production: { title: "Describe three things more naturally", steps: ["Describe a person with who.", "Describe an object with that or which.", "Describe a place with where."], model: "I admire a teacher who always gives practical examples. I also use an app that tracks my routine, and I like the cafe where I usually study." }, homework: "Write six sentences with relative clauses: two about people, two about things and two about places.", celebration: "Relative clauses help the learner sound more connected and less mechanical, which is a visible sign of B1 development." },
    { number: 14, unit: "Block 2", title: "Passive Voice in Everyday English", objective: "Use simple passive structures in common explanations, processes and news-like statements.", cefr: "Can understand and use simple passive forms in familiar contexts.", focus: "Present and past passive", warmup: "When do we focus more on the action than on the person who does it?", checkpoint: ["Use passive when the action is more important than the agent.", "Recognize passive language in processes and updates."], dialogueTitle: "How things are done", dialogue: [["Teacher", "How is the final report prepared in your team?"], ["Student", "First, the data is collected. Then it is reviewed by the manager."], ["Teacher", "And what happened last month?"], ["Student", "The report was delayed because one section was rewritten."]], grammar: { title: "Passive voice for process and focus", intro: "The passive is common when the doer is unknown, obvious or less important than the action itself.", points: [["Present passive", "am/is/are + past participle", "The emails are checked every morning."], ["Past passive", "was/were + past participle", "The package was delivered yesterday."], ["With by", "by + agent", "The poster was designed by Ana."], ["Common contexts", "rules, processes, news", "Payments are processed online."]] }, vocabTitle: "Processes and systems", vocabulary: [["deliver", "entregar", "The product was delivered late."], ["process", "processar", "Applications are processed every week."], ["review", "revisar", "The document was reviewed carefully."], ["collect", "coletar", "The data is collected automatically."], ["publish", "publicar", "The results were published online."], ["rewrite", "reescrever", "One section was rewritten."]], production: { title: "Explain a simple process", steps: ["Choose a common process such as paying a bill or sending a package.", "Describe two present passive steps.", "Add one past passive sentence about a recent problem or result."], model: "First, the request is submitted online. Then it is checked by the support team. Last week, one request was delayed because the system was updated." }, homework: "Write a simple process explanation with four passive sentences and one sentence with by to show the agent.", celebration: "The passive voice gives the learner access to a wider range of real-world texts and explanations often seen at B1." },
    { number: 15, unit: "Block 2", title: "News, Updates and Main Ideas", objective: "Summarize familiar news or updates and identify key information.", cefr: "Can understand the main points of clear factual information and summarize them simply.", focus: "Summarizing with main idea and detail", warmup: "When you read a short article or update, what details matter most first?", checkpoint: ["Separate the main idea from supporting detail.", "Use short summary language."], dialogueTitle: "Talking about an update", dialogue: [["Teacher", "What is the main news in the article?"], ["Student", "The main point is that the company is changing its work model."], ["Teacher", "What detail supports that?"], ["Student", "It says employees will work in the office two days a week."]], grammar: { title: "Useful summary language", intro: "Summaries at B1 do not need to be perfect. The goal is to identify the main point, key details and simple consequences.", points: [["Main idea", "The main point is...", "The main point is that costs have increased."], ["Supporting detail", "According to the text...", "According to the text, demand has grown."], ["Result", "As a result...", "As a result, the company changed its plan."], ["Simple reporting", "It says / It explains / It mentions", "It mentions two possible solutions."]] }, vocabTitle: "Reading and summary language", vocabulary: [["headline", "manchete", "The headline is clear and direct."], ["source", "fonte", "Check the source before sharing."], ["detail", "detalhe", "That detail supports the main idea."], ["summary", "resumo", "A good summary is short and clear."], ["report", "relatorio", "The report explains the change."], ["mention", "mencionar", "The article mentions a possible risk."]], production: { title: "Summarize a short update", steps: ["Say the main point.", "Add one detail from the text or message.", "Explain one result or implication."], model: "The main point is that the team is changing its schedule. According to the update, meetings will happen earlier, and as a result, the afternoon will be more flexible." }, homework: "Read a short article, announcement or company message and write a four-sentence summary using main point, one detail and one result.", celebration: "B1 learners need this skill often: not full analysis, but clear understanding of the main message and its practical meaning." },
    { number: 16, unit: "Block 2 Review", title: "Review 2: Communicate Clearly", objective: "Review opinions, decisions, comparison, expectations, relative clauses and simple passive structures.", cefr: "Can participate in practical discussion and describe familiar situations more clearly.", focus: "Integrated review", warmup: "Can you compare two ideas, express an opinion and suggest a next step in one short answer?", checkpoint: ["Use clearer linking language across ideas.", "Choose structures based on communication goal."], dialogueTitle: "A review conversation", dialogue: [["Teacher", "Which option seems more practical to you?"], ["Student", "In my opinion, the online plan is more flexible and affordable."], ["Teacher", "What should the team do next?"], ["Student", "They should test it for a month and review the results that are collected."]], grammar: { title: "Choosing the best tool", intro: "This review combines the structures that help B1 learners discuss, compare and explain ideas with more precision.", points: [["Discussion", "In my opinion / I see your point, but...", "In my opinion, this process is too slow."], ["Suggestion", "should / could / let's", "We could start with a simpler version."], ["Comparison", "more / less / too / enough", "The first plan is not flexible enough."], ["Description", "who / that / passive", "We need a system that is easy to use."]] }, vocabTitle: "Review and reflection", vocabulary: [["clarity", "clareza", "Clarity matters in team communication."], ["solution", "solucao", "This looks like a practical solution."], ["feedback", "feedback", "The feedback was collected yesterday."], ["improvement", "melhoria", "We can still make one improvement."], ["discussion", "discussao", "The discussion was respectful."], ["decision", "decisao", "The final decision was shared today."]], production: { title: "Discuss and decide", steps: ["Compare two options.", "Give your opinion politely.", "End with one suggestion or decision."], model: "The online option seems more practical because it is cheaper and flexible enough for most people. I understand the advantages of the face-to-face option, but I think we should start online and review the results later." }, homework: "Write a recommendation email comparing two options and suggesting one final decision.", celebration: "This review reinforces the language B1 learners need to function in practical discussion, not only classroom exercises." },
    { number: 17, unit: "Block 3", title: "Stories in Progress", objective: "Narrate actions that were in progress in the past and describe story context.", cefr: "Can narrate events and describe what was happening at a particular moment.", focus: "Past continuous and past simple", warmup: "What were you doing the last time something unexpected happened to you?", checkpoint: ["Use past continuous for background actions in progress.", "Use past simple for the interrupting event."], dialogueTitle: "An unexpected moment", dialogue: [["Teacher", "What were you doing when your phone rang?"], ["Student", "I was cooking dinner when my phone rang."], ["Teacher", "Did you answer right away?"], ["Student", "No, I turned off the stove first and then I answered."]], grammar: { title: "Background and interruption in the past", intro: "The past continuous sets the scene. The past simple shows the shorter completed action or interruption.", points: [["Action in progress", "was/were + verb-ing", "They were waiting outside."], ["Interrupting event", "past simple", "The bus arrived suddenly."], ["With when", "past continuous + when + past simple", "I was reading when she called."], ["Two background actions", "while + past continuous", "While I was working, she was studying."]] }, vocabTitle: "Storytelling language", vocabulary: [["interrupt", "interromper", "The call interrupted the meeting."], ["suddenly", "de repente", "Suddenly, the lights went out."], ["background", "contexto", "Give the background before the main event."], ["notice", "perceber", "I noticed the problem immediately."], ["happen", "acontecer", "Something strange happened."], ["react", "reagir", "She reacted calmly."]], production: { title: "Tell a short past scene", steps: ["Describe what you were doing.", "Add the interrupting event.", "Explain how you reacted."], model: "I was checking my email when the internet stopped working. At first, I thought it was a small problem, but then I restarted the router and solved it." }, homework: "Write a short story about an unexpected event using at least three past continuous forms and three past simple forms.", celebration: "Narration becomes richer when the learner can create background, interruption and reaction instead of listing events only." },
    { number: 18, unit: "Block 3", title: "Sequence and Background", objective: "Use past perfect to clarify order in stories.", cefr: "Can show sequence in past narratives when needed.", focus: "Past perfect basics with before and after", warmup: "When do we need an extra form to show that one past action happened earlier than another?", checkpoint: ["Use past perfect when one past action happened before another past action.", "Keep the structure simple and meaningful."], dialogueTitle: "What happened first?", dialogue: [["Teacher", "Why were you so tired yesterday?"], ["Student", "I was tired because I had gone to bed very late the night before."], ["Teacher", "Had you finished your work before that?"], ["Student", "Yes, I had finished it, but I stayed up watching videos."]], grammar: { title: "Past perfect for earlier past events", intro: "Use past perfect when the order of two past actions is important and you want to make the earlier action clear.", points: [["Earlier past", "had + past participle", "She had left before I arrived."], ["Negative", "had not + past participle", "We had not eaten before the trip."], ["Question", "Had + subject + past participle?", "Had they seen the message before the meeting?"], ["With before/after", "before / after + clause", "After he had checked the file, he sent it."]] }, vocabTitle: "Story sequence", vocabulary: [["earlier", "antes", "The earlier message was more helpful."], ["beforehand", "com antecedencia", "I should have prepared beforehand."], ["realize", "perceber", "I realized I had forgotten something."], ["arrive", "chegar", "She had already arrived."], ["leave", "sair", "They had left before noon."], ["sequence", "sequencia", "A clear sequence helps the listener."]], production: { title: "Clarify the order of events", steps: ["Choose a past situation with at least two actions.", "Explain what happened first with past perfect.", "Finish the story with past simple."], model: "When I got to the station, the train had already left. I checked the schedule again and took the next one." }, homework: "Write five short story sentences using past perfect to show which action happened earlier.", celebration: "This lesson gives the learner better control of storytelling sequence, which often appears in B1 speaking and writing tasks." },
    { number: 19, unit: "Block 3", title: "Reported Speech for Daily Conversations", objective: "Report what someone said in familiar situations.", cefr: "Can report the content of short statements, requests and questions simply.", focus: "Reported speech basics", warmup: "How often do you need to tell someone what another person said?", checkpoint: ["Report simple statements and requests.", "Focus on meaning, not only word-by-word repetition."], dialogueTitle: "Passing on a message", dialogue: [["Teacher", "What did your manager say?"], ["Student", "She said that the meeting would start earlier."], ["Teacher", "Did she ask for anything else?"], ["Student", "Yes. She told us to send the updated slides before noon."]], grammar: { title: "Simple reported speech", intro: "At B1, learners often need to report simple messages, instructions and questions in everyday contexts.", points: [["Statement", "said (that)...", "He said that he was tired."], ["Instruction", "told + object + to + verb", "She told me to wait."], ["Question", "asked if / asked what...", "They asked if I was available."], ["Meaning first", "clear reporting in context", "Focus on meaning more than perfect backshift."]] }, vocabTitle: "Messages and instructions", vocabulary: [["message", "mensagem", "I got a message from the office."], ["mention", "mencionar", "She mentioned a possible change."], ["warn", "avisar", "He warned us about the delay."], ["remind", "lembrar", "Please remind me tomorrow."], ["request", "pedido", "The request was simple."], ["instruction", "instrucao", "The instruction was clear."]], production: { title: "Report a short exchange", steps: ["Imagine someone gave you a message.", "Report one statement and one request.", "Add one reported question if possible."], model: "My colleague said that the client wanted a simpler version. She also told us to send a new draft by tomorrow and asked if I could review it tonight." }, homework: "Write a short paragraph reporting what a teacher, manager, friend or family member said and asked.", celebration: "Reported speech helps the learner function in real communication chains, where repeating information clearly matters." },
    { number: 20, unit: "Block 3", title: "Problems, Causes and Solutions", objective: "Explain a problem, its cause and a practical solution.", cefr: "Can describe a problem and explain possible solutions with simple reasons.", focus: "Cause, result and solution language", warmup: "What kinds of problems do you often need to explain in English?", checkpoint: ["State the problem clearly.", "Give one cause and one solution."], dialogueTitle: "Finding a practical solution", dialogue: [["Teacher", "What is the main problem with the project?"], ["Student", "The main problem is that the deadlines are too close together."], ["Teacher", "Why is that happening?"], ["Student", "Because the tasks were divided badly. We need to reorganize the schedule."]], grammar: { title: "Explaining cause and solution", intro: "This lesson focuses on communicative patterns that B1 learners need often in work, study and daily life.", points: [["State the problem", "The problem is that...", "The problem is that communication is slow."], ["Give a cause", "because / due to / since", "It happened because the team changed late."], ["Give a result", "so / therefore", "So we missed the deadline."], ["Offer a solution", "We should / We need to / One solution is...", "One solution is to simplify the process."]] }, vocabTitle: "Solving everyday problems", vocabulary: [["issue", "problema", "There is an issue with the payment system."], ["cause", "causa", "We still need to identify the cause."], ["delay", "atraso", "The delay created new problems."], ["solve", "resolver", "We should solve this quickly."], ["improve", "melhorar", "A small change could improve the process."], ["reorganize", "reorganizar", "They need to reorganize the tasks."]], production: { title: "Explain a real problem", steps: ["State one real or imagined problem.", "Give one possible cause.", "Offer one practical solution."], model: "The problem is that our meetings often start late because people do not have the agenda in advance. One solution is to share the agenda earlier and keep the first five minutes for questions only." }, homework: "Write a short problem-solution paragraph about study, work, transport, health or technology.", celebration: "Problem-solution language is essential at B1 because it appears in speaking tasks, emails and real conversations all the time." },
    { number: 21, unit: "Block 3", title: "Travel Plans and Unexpected Issues", objective: "Talk through travel arrangements and common travel problems.", cefr: "Can handle most situations likely to arise while traveling.", focus: "Travel communication and problem-solving", warmup: "What travel problems have you had or worried about before?", checkpoint: ["Ask for help in a practical way.", "Explain what happened and what you need."], dialogueTitle: "At the service desk", dialogue: [["Teacher", "What seems to be the problem?"], ["Student", "My flight was delayed, and I have missed my connection."], ["Teacher", "What do you need now?"], ["Student", "I need to know if I can take the next flight or get a hotel voucher."]], grammar: { title: "Useful patterns for travel problems", intro: "Travel conversations often mix past explanation, present need and polite requests.", points: [["Explain the issue", "My flight was delayed / I have missed...", "My luggage was sent to another city."], ["Ask for options", "Can I...?/ Is it possible to...?", "Is it possible to change the booking?"], ["State a need", "I need to / I would like to", "I would like to know the next step."], ["Polite follow-up", "Could you tell me...?", "Could you tell me where to wait?"]] }, vocabTitle: "Travel situations", vocabulary: [["connection", "conexao", "I missed my connection."], ["voucher", "voucher", "The hotel voucher covered one night."], ["boarding pass", "cartao de embarque", "Please show your boarding pass."], ["delay", "atraso", "There was a long delay."], ["luggage", "bagagem", "My luggage did not arrive."], ["rebook", "remarcar", "Can you rebook my flight?"]], production: { title: "Handle a travel issue", steps: ["Explain what went wrong.", "Say what you need now.", "Ask one polite follow-up question."], model: "My flight was delayed, and I have missed my connection. I need to know if I can travel tonight, and I would also like to ask whether you can help with accommodation." }, homework: "Write a short airport or hotel role-play with one problem, one request and one follow-up question.", celebration: "This lesson targets a classic CEFR B1 can-do: dealing with likely travel situations using practical language." },
    { number: 22, unit: "Block 3", title: "Health, Stress and Wellbeing", objective: "Describe symptoms, habits and advice related to wellbeing.", cefr: "Can describe symptoms, habits and simple health concerns, and ask for or give advice.", focus: "Health language plus advice", warmup: "What habits help you feel better physically or mentally?", checkpoint: ["Describe simple symptoms and daily habits.", "Give practical advice clearly."], dialogueTitle: "Talking about wellbeing", dialogue: [["Teacher", "How have you been feeling lately?"], ["Student", "I have been feeling tired and stressed because I am sleeping badly."], ["Teacher", "What do you think would help?"], ["Student", "I think I should rest more and stop checking my phone so late."]], grammar: { title: "Describing symptoms and giving advice", intro: "Health conversations at B1 often combine present perfect for recent patterns, present continuous for current situations and should for advice.", points: [["Recent pattern", "have been + adjective / verb-ing", "I have been feeling exhausted."], ["Current action", "am/is/are + verb-ing", "I am sleeping only five hours."], ["Advice", "should / should not", "You should drink more water."], ["Cause", "because / due to", "I am stressed because of work."]] }, vocabTitle: "Wellbeing and balance", vocabulary: [["stressed", "estressado", "She has been very stressed lately."], ["tired", "cansado", "I still feel tired in the morning."], ["rest", "descanso", "You need more rest."], ["routine", "rotina", "A good routine helps a lot."], ["habit", "habito", "Small habits can improve sleep."], ["balance", "equilibrio", "Work-life balance is important."]], production: { title: "Describe a wellbeing issue", steps: ["Say how you have been feeling.", "Explain one possible reason.", "Give yourself or someone else advice."], model: "I have been feeling more tired lately because I am using screens too late at night. I think I should change my evening routine and rest more." }, homework: "Write a short wellbeing plan with one problem, one cause and three pieces of advice.", celebration: "The learner is practicing practical personal language here, which is very common in B1 speaking and everyday interaction." },
    { number: 23, unit: "Block 3", title: "Study, Work and Career Paths", objective: "Describe work experience, strengths and future professional plans.", cefr: "Can describe work experience, goals and preferences in familiar professional contexts.", focus: "Career vocabulary and connected answers", warmup: "What matters more to you in a job: salary, flexibility, growth or stability?", checkpoint: ["Describe experience and goals with more detail.", "Connect strengths, preferences and future plans."], dialogueTitle: "A career conversation", dialogue: [["Teacher", "What kind of work environment suits you best?"], ["Student", "I work best in organized teams where communication is clear."], ["Teacher", "What are you hoping to do next?"], ["Student", "I would like to move into a role with more responsibility and learning opportunities."]], grammar: { title: "Useful structures for career talk", intro: "Career communication at B1 often combines present simple for preferences, present perfect for experience and would like for goals.", points: [["Preference", "I work best when... / I prefer...", "I prefer tasks with clear deadlines."], ["Experience", "I have worked / I have learned...", "I have learned how to manage clients."], ["Goal", "I would like to...", "I would like to develop leadership skills."], ["Strength", "I am good at...", "I am good at organizing information."]] }, vocabTitle: "Career development", vocabulary: [["responsibility", "responsabilidade", "I am ready for more responsibility."], ["skill", "habilidade", "Communication is an important skill."], ["strength", "ponto forte", "Organization is one of my strengths."], ["experience", "experiencia", "I have useful customer service experience."], ["opportunity", "oportunidade", "This role offers learning opportunities."], ["growth", "crescimento", "I am looking for professional growth."]], production: { title: "Present yourself professionally", steps: ["Describe your current experience.", "Mention one strength.", "Say what you would like to do next."], model: "I have worked with customers for a few years, and I have learned to communicate clearly under pressure. One of my strengths is organization, and I would like to move into a role with more planning responsibilities." }, homework: "Write a short self-introduction for a class, interview or networking event using experience, strength and future goal language.", celebration: "Career language is important at B1 because it appears in interviews, introductions, presentations and many real-life conversations." },
    { number: 24, unit: "Block 3 Review", title: "Review 3: Real-World Communication", objective: "Review storytelling, sequence, reported speech, problem-solving, travel and wellbeing communication.", cefr: "Can narrate, report and solve familiar real-life situations with better control.", focus: "Integrated review", warmup: "Can you tell a short story, report a message and explain a solution in one conversation?", checkpoint: ["Keep stories and explanations organized.", "Choose the correct communication pattern for the goal."], dialogueTitle: "Putting it all together", dialogue: [["Teacher", "What happened during your trip last weekend?"], ["Student", "I was waiting at the station when the train was canceled."], ["Teacher", "What did the staff say?"], ["Student", "They said that another train would leave later, so I changed my plan."]], grammar: { title: "Narrate, report and solve", intro: "This review combines the grammar and communication patterns that help B1 learners manage real situations more independently.", points: [["Story background", "past continuous + past simple", "I was waiting when the announcement came."], ["Earlier past", "past perfect", "The train had already left from another platform."], ["Reported message", "said / told / asked", "They told us to wait."], ["Practical solution", "The problem is... / One solution is...", "One solution is to check the app earlier."]] }, vocabTitle: "Real-life review set", vocabulary: [["announcement", "anuncio", "The announcement came late."], ["message", "mensagem", "The message was not clear."], ["delay", "atraso", "The delay affected everyone."], ["solution", "solucao", "We found a simple solution."], ["stress", "estresse", "The situation created a lot of stress."], ["adjust", "ajustar", "I had to adjust my schedule."]], production: { title: "Tell, report and solve", steps: ["Describe a short problem situation.", "Report what someone said.", "Finish with the solution."], model: "I was trying to check in when the system stopped working. A staff member told us to wait near the desk, and in the end they solved the issue by processing people manually." }, homework: "Write a short real-life narrative that includes what was happening, what someone said and how the problem was solved.", celebration: "By this point, the learner can handle much more realistic communication chains, which is one of the strongest signs of B1 progress." },
    { number: 25, unit: "Block 4", title: "Technology and Digital Habits", objective: "Discuss digital routines, benefits, risks and preferences.", cefr: "Can discuss familiar topics such as technology and habits with reasons and examples.", focus: "Opinions and frequency in technology contexts", warmup: "How has technology changed the way you study, work or relax?", checkpoint: ["Describe digital habits and preferences clearly.", "Explain benefits and drawbacks with examples."], dialogueTitle: "A digital routine", dialogue: [["Teacher", "How often do you use AI or digital tools to study?"], ["Student", "I use them regularly, especially when I need quick examples or feedback."], ["Teacher", "Do you think that is always positive?"], ["Student", "Not always. It is useful, but people should still think critically."]], grammar: { title: "Discussing habits and opinions", intro: "Technology topics at B1 often require frequency language, opinion language and simple cause-result explanations.", points: [["Frequency", "regularly / often / once in a while", "I check messages too often."], ["Benefit", "It helps me... / It allows me to...", "It allows me to save time."], ["Drawback", "The problem is that...", "The problem is that it can distract me."], ["Balanced view", "useful, but / however", "It is useful, but it is not perfect."]] }, vocabTitle: "Digital life", vocabulary: [["device", "dispositivo", "I use several devices every day."], ["notification", "notificacao", "Too many notifications break my focus."], ["screen time", "tempo de tela", "I am trying to reduce my screen time."], ["distract", "distrair", "Social media can distract students."], ["tool", "ferramenta", "This tool saves time."], ["critical thinking", "pensamento critico", "Technology should support critical thinking."]], production: { title: "Describe your digital habits", steps: ["Mention one useful tool or habit.", "Mention one risk or drawback.", "Give one recommendation for balance."], model: "I use digital tools regularly because they help me organize information quickly. At the same time, I know screen time can distract me, so I try to set limits during the evening." }, homework: "Write a short reflection about your digital habits using one benefit, one drawback and one strategy for balance.", celebration: "Technology is a highly familiar B1 topic, and discussing it helps the learner sound more current and independent." },
    { number: 26, unit: "Block 4", title: "The Environment and Responsible Choices", objective: "Discuss simple environmental issues and personal choices.", cefr: "Can discuss familiar environmental topics and explain simple actions and reasons.", focus: "Cause, effect and responsibility language", warmup: "What environmental habits are realistic for most people in daily life?", checkpoint: ["Talk about environmental habits in simple, realistic language.", "Link actions to reasons and effects."], dialogueTitle: "Small actions, bigger effects", dialogue: [["Teacher", "Do small habits really make a difference?"], ["Student", "I think they do, especially when many people change together."], ["Teacher", "What action is easiest to start with?"], ["Student", "Using less plastic is a good start because it is practical for most people."]], grammar: { title: "Explaining environmental choices", intro: "At B1, the goal is not advanced science language. The learner should explain everyday actions, causes and effects clearly.", points: [["General opinion", "I think / I believe", "I think public transport should improve."], ["Reason", "because / since", "It matters because waste affects everyone."], ["Effect", "so / as a result", "So people need better options."], ["Responsibility", "should / need to", "We need to reduce unnecessary waste."]] }, vocabTitle: "Environment and habits", vocabulary: [["waste", "desperdicio", "We create too much waste."], ["recycle", "reciclar", "Many families recycle regularly."], ["reuse", "reutilizar", "Reusable bottles help reduce plastic."], ["reduce", "reduzir", "We should reduce energy use."], ["resource", "recurso", "Water is a limited resource."], ["sustainable", "sustentavel", "Small sustainable habits matter."]], production: { title: "Explain one responsible choice", steps: ["Choose one daily habit connected to the environment.", "Explain why it matters.", "Suggest one realistic action."], model: "Using less disposable plastic matters because it reduces waste over time. A simple step is carrying a reusable bottle or bag when possible." }, homework: "Write a short practical guide with four environmentally responsible habits and one reason for each.", celebration: "This lesson gives the learner a useful B1 topic for discussion, opinion sharing and personal action." },
    { number: 27, unit: "Block 4", title: "Money, Shopping and Smart Decisions", objective: "Compare products, explain spending choices and discuss financial priorities.", cefr: "Can discuss purchases, preferences and practical financial decisions in familiar contexts.", focus: "Budget language and decision-making", warmup: "When you buy something important, what matters most: price, quality or long-term value?", checkpoint: ["Explain why one option is worth it or not.", "Use comparison and budgeting vocabulary."], dialogueTitle: "Thinking before buying", dialogue: [["Teacher", "Why did you choose the cheaper option?"], ["Student", "Because it was affordable and still good enough for what I needed."], ["Teacher", "Would you ever spend more on a similar product?"], ["Student", "Yes, if the quality was clearly better and it lasted longer."]], grammar: { title: "Explaining spending choices", intro: "B1 learners often need language for comparing value, explaining priorities and making practical decisions.", points: [["Budget priority", "I need / I want / I can afford", "I can afford the basic version."], ["Value comparison", "worth it / better value", "The second option seems worth it."], ["Condition", "if", "I would buy it if the price dropped."], ["Limit", "too expensive / good enough", "It is too expensive right now."]] }, vocabTitle: "Shopping and value", vocabulary: [["budget", "orcamento", "My budget is limited this month."], ["afford", "poder pagar", "I can afford the cheaper one."], ["worth it", "vale a pena", "It is expensive, but it is worth it."], ["discount", "desconto", "I bought it with a discount."], ["quality", "qualidade", "The quality is much better."], ["last", "durar", "A better product usually lasts longer."]], production: { title: "Explain a buying decision", steps: ["Choose one product or service.", "Compare two options.", "Explain which one you would choose and why."], model: "I would choose the mid-range option because it is more affordable than the premium one, but still reliable enough for daily use. For me, that is the best value." }, homework: "Write a short comparison of two products or services using budget, quality and worth-it language.", celebration: "This topic is highly practical and gives the learner more confidence in real-world decisions and everyday conversation." },
    { number: 28, unit: "Block 4", title: "Relationships and Social Situations", objective: "Talk about friendship, communication and social misunderstandings more naturally.", cefr: "Can describe relationships, social situations and feelings in familiar terms.", focus: "Social language and explanation", warmup: "What makes communication easier or harder in friendships and group situations?", checkpoint: ["Describe social situations with simple emotional nuance.", "Explain misunderstandings and reactions."], dialogueTitle: "A social misunderstanding", dialogue: [["Teacher", "Why did the conversation become uncomfortable?"], ["Student", "Because one person interrupted too much and the others felt ignored."], ["Teacher", "What could help in situations like that?"], ["Student", "People should listen more carefully and give everyone time to speak."]], grammar: { title: "Explaining feelings and social reactions", intro: "B1 learners often need to describe not just what happened, but how people felt and what could improve the interaction.", points: [["Cause of feeling", "felt + adjective because...", "She felt annoyed because he interrupted."], ["Social advice", "should / should not", "You should listen before reacting."], ["General truth", "when people...", "When people feel respected, they speak more openly."], ["Result", "so", "He was nervous, so he spoke too fast."]] }, vocabTitle: "Social interaction", vocabulary: [["respectful", "respeitoso", "A respectful tone changes everything."], ["interrupt", "interromper", "Please do not interrupt people."], ["ignore", "ignorar", "No one likes to feel ignored."], ["awkward", "constrangedor", "The silence felt awkward."], ["openly", "abertamente", "They talked openly about the issue."], ["misunderstanding", "mal-entendido", "It was just a misunderstanding."]], production: { title: "Describe a social situation", steps: ["Describe what happened.", "Explain how people felt.", "Give one suggestion for better communication."], model: "The discussion became awkward because two people kept interrupting each other. Everyone felt uncomfortable, and I think it would have helped if they had slowed down and listened more carefully." }, homework: "Write about a social situation that went well or badly and explain what made the difference.", celebration: "This lesson helps the learner manage a common B1 need: talking about relationships and interaction beyond very basic language." },
    { number: 29, unit: "Block 4", title: "Wishes, Regrets and Possibilities", objective: "Use hypothetical language for wishes, regrets and unreal possibilities.", cefr: "Can talk about imaginary situations, wishes and regrets in a simple way.", focus: "Second conditional and wish", warmup: "What would you change if you had more time, money or confidence right now?", checkpoint: ["Use second conditional for unreal present or future situations.", "Use wish for present regrets or desires."], dialogueTitle: "If things were different", dialogue: [["Teacher", "What would you do if you had a month free?"], ["Student", "I would travel and spend more time reading."], ["Teacher", "Is there anything you wish were different now?"], ["Student", "Yes, I wish I had a little more free time during the week."]], grammar: { title: "Imagined situations and wishes", intro: "Second conditional helps B1 learners move into more reflective and hypothetical language. Wish adds a simple way to express regret or desire.", points: [["Hypothetical", "If + past simple, would + base verb", "If I had more time, I would cook more."], ["Reverse order", "would + base verb if + past simple", "I would rest more if my schedule were lighter."], ["Wish now", "wish + past simple", "I wish I lived closer to work."], ["Advice-like regret", "If I were you...", "If I were you, I would start earlier."]] }, vocabTitle: "Reflection and possibility", vocabulary: [["wish", "desejo", "I wish weekends felt longer."], ["regret", "arrependimento", "He regrets wasting so much time."], ["opportunity", "oportunidade", "More time would create new opportunities."], ["choice", "escolha", "Every choice has a cost."], ["freedom", "liberdade", "More freedom would change my routine."], ["imagine", "imaginar", "Imagine if you could work anywhere."]], production: { title: "Reflect on an unreal possibility", steps: ["Describe one hypothetical change with if.", "Say what you would do.", "Add one wish about your current life."], model: "If I had a more flexible routine, I would study earlier in the day and exercise more often. I also wish I had fewer distractions in the evening." }, homework: "Write six sentences: three second conditional ideas and three wish sentences about your current life.", celebration: "Hypothetical language gives the learner more expressive power and is a classic milestone in B1 development." },
    { number: 30, unit: "Block 4", title: "Presenting and Persuading", objective: "Organize a short persuasive message or mini presentation.", cefr: "Can briefly give reasons and explanations for opinions and plans.", focus: "Linkers and persuasive structure", warmup: "What makes a short presentation clear and convincing?", checkpoint: ["Organize ideas with simple linkers.", "Support one main idea with reasons and examples."], dialogueTitle: "A simple persuasive message", dialogue: [["Teacher", "Why do you think your idea should be chosen?"], ["Student", "First, it is more practical. Second, it costs less and saves time."], ["Teacher", "Can you give one example?"], ["Student", "Yes. For example, our team could start using it next week without special training."]], grammar: { title: "Structure for short persuasive speaking", intro: "At B1, the goal is not advanced rhetoric. A simple clear structure with linkers can already sound strong and organized.", points: [["Opening", "I think / My main point is...", "My main point is that this option is more practical."], ["Sequencing", "first / second / finally", "First, it is easy to use."], ["Examples", "for example / for instance", "For example, students can access it from home."], ["Conclusion", "So / That is why / Therefore", "That is why I recommend this plan."]] }, vocabTitle: "Presentation language", vocabulary: [["convince", "convencer", "Good examples can convince people."], ["clear", "claro", "Your message should be clear."], ["organized", "organizado", "An organized talk is easier to follow."], ["reason", "razao", "Give one strong reason first."], ["example", "exemplo", "A concrete example helps a lot."], ["recommend", "recomendar", "I recommend the simpler option."]], production: { title: "Give a mini persuasive talk", steps: ["State your main point.", "Give two reasons.", "Add one example and a conclusion."], model: "My main point is that a shorter study routine can be more effective. First, it is easier to maintain. Second, it reduces stress. For example, twenty focused minutes every day may work better than one long session once a week. That is why I recommend a simpler routine." }, homework: "Write and practice a one-minute persuasive talk about a study method, app, routine or practical solution.", celebration: "This lesson supports a key B1 can-do: giving brief reasons and explanations for opinions and plans." },
    { number: 31, unit: "Block 4", title: "Final Project Workshop", objective: "Prepare to integrate personal experience, opinion, explanation and future plans in a final B1 task.", cefr: "Can prepare a short connected presentation about familiar topics, experiences and goals.", focus: "Planning and organizing a final performance", warmup: "What topic would let you show your best B1 communication right now?", checkpoint: ["Select a familiar topic you can really talk about.", "Organize your message into a clear beginning, middle and end."], dialogueTitle: "Planning the final task", dialogue: [["Teacher", "What topic do you want to use for your final project?"], ["Student", "I want to talk about how my study routine has changed and what I plan to do next."], ["Teacher", "Why is that a strong topic?"], ["Student", "Because I can describe real experience, give opinions and explain my goals."]], grammar: { title: "Combining B1 tools in one task", intro: "A strong B1 final task mixes personal experience, explanation, opinion and future intention in a simple but organized structure.", points: [["Opening", "Introduce the topic and main idea", "Today I want to talk about how my routine has changed."], ["Middle", "Give examples, reasons and one challenge", "At first, I used to study without a plan."], ["Reflection", "Add opinion or lesson learned", "I think consistency matters more than intensity."], ["Closing", "Mention a next step", "Next, I am going to keep this habit and improve speaking."]] }, vocabTitle: "Project preparation", vocabulary: [["structure", "estrutura", "A simple structure helps the listener."], ["main idea", "ideia principal", "Start with one main idea."], ["example", "exemplo", "Add a real example to support your point."], ["challenge", "desafio", "Mention one challenge honestly."], ["goal", "meta", "Finish with a realistic goal."], ["confidence", "confianca", "Practice helps build confidence."]], production: { title: "Outline your final presentation", steps: ["Choose your topic.", "Plan an opening, two middle points and one closing idea.", "Practice saying it aloud with steady pace and clear transitions."], model: "Today I want to talk about how my routine changed this year. I used to study without consistency, but I have become more organized. I think shorter and regular practice works better for me, and next I am going to focus more on speaking." }, homework: "Write the first full version of your final B1 presentation or paragraph and practice it twice aloud.", celebration: "This workshop prepares the learner to show B1 communication as a whole, not only isolated grammar points." },
    { number: 32, unit: "Final Checkpoint", title: "B1 Final Project and Can-Do Check", objective: "Consolidate the full B1 path with an integrated task and self-check of core CEFR can-do goals.", cefr: "Can deal with familiar situations, connect ideas, explain opinions and describe experiences and plans with reasonable clarity.", focus: "Integrated final performance", warmup: "What can you do in English now that felt hard at the start of the B1 module?", checkpoint: ["Describe experiences, opinions, problems and plans in connected speech.", "Use familiar B1 structures with growing independence."], dialogueTitle: "Looking back and moving forward", dialogue: [["Teacher", "How has your English changed during this module?"], ["Student", "I can explain ideas more clearly, compare options and tell stories with more detail now."], ["Teacher", "What do you still want to improve?"], ["Student", "I want to become faster in conversation, but I already feel much more independent than before."]], grammar: { title: "What a B1 learner can now combine", intro: "At the end of B1, the learner should not be perfect, but they should be able to combine familiar structures to communicate meaning with relative confidence.", points: [["Experiences", "present perfect / past simple", "I have learned a lot, and last month I gave my first full presentation."], ["Opinions and reasons", "I think... because...", "I think short daily practice works best because it is easier to maintain."], ["Problem and solution", "The problem is... / We should...", "The problem is time, so we should simplify the plan."], ["Goals", "I am going to / I would like to", "I would like to improve fluency next."]] }, vocabTitle: "B1 reflection set", vocabulary: [["independent", "independente", "I feel more independent now."], ["fluency", "fluencia", "My fluency is improving slowly."], ["confidence", "confianca", "Practice has given me more confidence."], ["progress", "progresso", "The progress is real, even if it is gradual."], ["goal", "meta", "My next goal is more spontaneous speaking."], ["connection", "conexao", "I can create better connections between ideas."]], production: { title: "Final B1 task", steps: ["Introduce a familiar topic connected to your life.", "Describe one past change, one current habit and one future goal.", "Add one opinion or lesson learned and finish with a confident conclusion."], model: "Over this module, my English routine has changed a lot. I used to study without much structure, but now I practice more regularly and I can explain my ideas better. I think consistency has helped me most, and next I would like to improve my fluency in longer conversations." }, homework: "Record or write your final B1 self-presentation and note three strengths and two next goals for the transition to B2.", celebration: "This final lesson closes the B1 stage with a clear message: the learner can now function with more independence, clearer organization and stronger communicative control." }
];
